CREATE OR REPLACE VIEW `prj-dbi-prd-1.ds_dbi_digitalmedia_automation.vw_sdi_pulse_bronze_pulseTab1_appendix`
OPTIONS(description="Bronze: raw appendix data mirroring the Pulse 1.2 Excel sheet. One row per metric or glossary term. apx_build_labels and apx_build_details store bullet labels/details as newline-joined strings. Edit here when content changes.")
AS SELECT * FROM(
SELECT 1 AS apx_sort_order,'mfc_spend_postpaid' AS apx_id,'MFC Spend - Postpaid' AS apx_label,'Metric' AS apx_record_type,'Top Funnel' AS apx_funnel_stage,1 AS apx_funnel_sort,'Media Spend' AS apx_category,1 AS apx_category_sort,'Postpaid LOB' AS apx_scope,'Postpaid' AS apx_lob,FALSE AS apx_is_subflow,CAST(NULL AS STRING) AS apx_parent_id,TRUE AS apx_subflows_summable,'Media Flow Chart (MFC)' AS apx_source_system,'Databricks' AS apx_source_platform,'prdrzranalytics.lab42.raw_media_flowchart' AS apx_source_table,'Amy Pritchett / Will Butler' AS apx_data_owner,'Weekly - finalized 3 PM PT Friday' AS apx_refresh_cadence,'Total dollars invested in Postpaid media each week, as tracked and finalized by LOB teams in the Media Flow Chart.' AS apx_definition,CAST(NULL AS STRING) AS apx_sum_warning,CAST(NULL AS STRING) AS apx_cvr_numerator_id,CAST(NULL AS STRING) AS apx_cvr_denominator_id,'SOURCE & QA\nLOB TEAMS\nUPDATES\nTACTIC FILTER\nCHANNEL FILTER\nFORECASTED SPEND\nACT VS FCST %\nQTD SUM' AS apx_build_labels,'Media Flow Chart (MFC) - T-Mobile centralized media spend source of truth, stored in Databricks.\nContribute Postpaid spend data each Thursday. QA and finalization by 3 PM PT Friday.\nWill Butler team performs twice-weekly updates for mid-week corrections.\nGlobal selector affecting all spend rows.\nApplies to MFC Spend only - does not affect any other metric.\nPlanned/budgeted amount from MFC.\n(Actuals minus Forecast) / Forecast.\nRunning total of weekly actuals from Q2 start.' AS apx_build_details,'MICRO EXCLUSION' AS apx_excl_labels,'Excludes Message_Type = MICRO and Message values SEM Postpaid/Micro and Micro Postpaid Offers until channel mapping is finalized.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
UNION ALL SELECT 2 AS apx_sort_order,'mfc_spend_broadband' AS apx_id,'MFC Spend - Broadband' AS apx_label,'Metric' AS apx_record_type,'Top Funnel' AS apx_funnel_stage,1 AS apx_funnel_sort,'Media Spend' AS apx_category,2 AS apx_category_sort,'Broadband / HSI LOB' AS apx_scope,'HSI' AS apx_lob,FALSE AS apx_is_subflow,CAST(NULL AS STRING) AS apx_parent_id,TRUE AS apx_subflows_summable,'Media Flow Chart (MFC)' AS apx_source_system,'Databricks' AS apx_source_platform,'prdrzranalytics.lab42.raw_media_flowchart' AS apx_source_table,'Amy Pritchett / Will Butler' AS apx_data_owner,'Weekly - finalized 3 PM PT Friday' AS apx_refresh_cadence,'Total dollars invested in Broadband (Home Internet) media each week, as tracked and finalized in the Media Flow Chart.' AS apx_definition,CAST(NULL AS STRING) AS apx_sum_warning,CAST(NULL AS STRING) AS apx_cvr_numerator_id,CAST(NULL AS STRING) AS apx_cvr_denominator_id,'SOURCE\nLOB TEAMS\nAGGREGATION\nFORECASTED SPEND\nACT VS FCST %' AS apx_build_labels,'Same source and build logic as MFC Spend - Postpaid, filtered to the Broadband LOB.\nSame LOB contribution, QA, and refresh cadence as Postpaid spend.\nAggregates weekly spend across all channels for the Broadband / HSI line of business.\nPlanned/budgeted Broadband amount.\n(Actuals minus Forecast) / Forecast.' AS apx_build_details,'MICRO EXCLUSION' AS apx_excl_labels,'Same MICRO message type exclusions as Postpaid MFC Spend.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
UNION ALL SELECT 3 AS apx_sort_order,'uvnb_actuals_overall' AS apx_id,'UVNB Actuals (Overall)' AS apx_label,'Metric' AS apx_record_type,'Top Funnel' AS apx_funnel_stage,1 AS apx_funnel_sort,'UVNB' AS apx_category,3 AS apx_category_sort,'All Flows Combined' AS apx_scope,'All' AS apx_lob,FALSE AS apx_is_subflow,CAST(NULL AS STRING) AS apx_parent_id,FALSE AS apx_subflows_summable,'Adobe Analytics -> BigQuery' AS apx_source_system,'BigQuery' AS apx_source_platform,'prj-dbi-prd-1.ds_dbi_digitalmedia_automation.vw_sdi_bronze_uvnbQgpActualsForecasts_weekly' AS apx_source_table,'Khalid / Ben' AS apx_data_owner,'Weekly - notebook run' AS apx_refresh_cadence,'Count of distinct website visitors who landed on T-Mobile.com and engaged beyond their first page - the broadest measure of qualified prospect traffic entering the funnel.' AS apx_definition,'IMPORTANT: Cannot sum Postpaid + HSI + BYOD flows to equal this total. Adobe deduplicates Unique Visitors at the scope of the metric.' AS apx_sum_warning,CAST(NULL AS STRING) AS apx_cvr_numerator_id,CAST(NULL AS STRING) AS apx_cvr_denominator_id,'UNIVERSAL FILTERS\nLAYER 1\nLAYER 2\nLAYER 3\nLAYER 4\nNO FLOW FILTER\nWOW %\nAVG OF QTD\nREFRESH' AS apx_build_labels,'DDM Exclude Data Issue + [DA] Web Visits + [sdi] Postpaid (Exclude TFB).\nExclude TMO Mobile Network Carrier - removes VISITS where Mobile Carrier Network = T-Mobile.\n[sdi] Exclude Authenticated VISITS - removes sessions where User State = Authenticated or any LOA token (LOA0.5 to LOA3) is present.\n[sdi] Exclude Visit Login Page - removes VISITS where Page URL contains associated_billing_accounts, t-mobile.com/guest-pay, or account.t-mobile.com/signin/v2/.\n[DA] Exclude Single Page Visits - removes VISITS where Single Page Visits exists. Enforces the Non-Bounced qualifier.\nBroadest universe across all product areas.\n(Current week minus Prior week) / Prior week.\nRunning average of weekly actuals from Q2 start.\nWeekly, each time the UVNB forecast notebook is run.' AS apx_build_details,'T-MOBILE NETWORK VISITORS\nAUTHENTICATED/LOA SESSIONS\nLOGIN & GUEST-PAY PAGES\nSINGLE-PAGE BOUNCES\nNATIVE APP TRAFFIC\nTFB PAGES' AS apx_excl_labels,'Visitors on the T-Mobile cellular network.\nAll sessions where User State = Authenticated or any LOA token present.\nAll visits touching sign-in or guest-pay pages.\nSessions with only one page view.\niOS/Android T-Life, MyT-Mobile, Metro app sessions.\nb2b, Atwork, /business, /t-priority URL paths.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
UNION ALL SELECT 4 AS apx_sort_order,'uvnb_forecasts' AS apx_id,'UVNB Forecasts' AS apx_label,'Metric' AS apx_record_type,'Top Funnel' AS apx_funnel_stage,1 AS apx_funnel_sort,'UVNB' AS apx_category,4 AS apx_category_sort,'All Flows' AS apx_scope,'All' AS apx_lob,FALSE AS apx_is_subflow,CAST(NULL AS STRING) AS apx_parent_id,FALSE AS apx_subflows_summable,'Adobe Analytics -> BigQuery (MFC WoW Spend% indexed to Adobe base)' AS apx_source_system,'BigQuery' AS apx_source_platform,'prj-dbi-prd-1.ds_dbi_digitalmedia_automation.vw_sdi_bronze_uvnbQgpActualsForecasts_weekly' AS apx_source_table,'Khalid / Ben' AS apx_data_owner,'Weekly - same notebook run as UVNB Actuals' AS apx_refresh_cadence,'A modeled weekly estimate of expected UVNB, used to benchmark whether actual traffic is tracking ahead or behind plan.' AS apx_definition,'Spend-indexed proxy - treat variance directionally. Model will be replaced once UVNB lands in a permanent table.' AS apx_sum_warning,CAST(NULL AS STRING) AS apx_cvr_numerator_id,CAST(NULL AS STRING) AS apx_cvr_denominator_id,'MODEL TYPE\nSTEP 1\nSTEP 2\nPROXY NOTE\nACT VS FCST %\nACT VS FCST DELTA\nREFRESH' AS apx_build_labels,'Interim forecast model - not a statistical model.\nTakes the WoW % change in MFC Spend vs the same week in the prior quarter.\nCompounds that change as an index applied to a prior-quarter UVNB anchor value.\nProxy until UVNB is fully landed in a permanent source table - historically-derived model will replace it.\n(Actuals minus Forecast) / Forecast.\nActuals minus Forecast in raw visitor count.\nWeekly, same notebook run as UVNB Actuals.' AS apx_build_details,'PROXY MODEL' AS apx_excl_labels,'Spend-indexed proxy - treat variance directionally. Model will be replaced once UVNB lands in a permanent table.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
UNION ALL SELECT 5 AS apx_sort_order,'uvnb_postpaid_flow' AS apx_id,'UVNB - Postpaid Flow' AS apx_label,'Metric' AS apx_record_type,'Top Funnel' AS apx_funnel_stage,1 AS apx_funnel_sort,'UVNB' AS apx_category,5 AS apx_category_sort,'Postpaid' AS apx_scope,'Postpaid' AS apx_lob,TRUE AS apx_is_subflow,'uvnb_actuals_overall' AS apx_parent_id,FALSE AS apx_subflows_summable,'Adobe Analytics -> BigQuery' AS apx_source_system,'BigQuery' AS apx_source_platform,'prj-dbi-prd-1.ds_dbi_digitalmedia_automation.vw_sdi_bronze_uvnbQgpActualsForecasts_weekly' AS apx_source_table,'Khalid / Ben' AS apx_data_owner,'Weekly - notebook run' AS apx_refresh_cadence,'Distinct non-bounced visitors who browsed the core Postpaid phone/plan shopping experience, with HSI pages excluded.' AS apx_definition,'Cannot be summed with HSI and BYOD flows to equal UVNB Actuals.' AS apx_sum_warning,'cart_postpaid_flow' AS apx_cvr_numerator_id,'uvnb_postpaid_flow' AS apx_cvr_denominator_id,'LAYER 1\nLAYER 2\nLAYER 3 - HSI EXCLUSION\nHSI PAGE NAME\nHSI PAGE URL\nHSI SITE SECTION\nHSI PRODUCT TYPE\nBYOD NOTE\nCVR DENOMINATOR' AS apx_build_labels,'Universal filters.\nProspect qualifiers: Exclude TMO Mobile Network Carrier + [sdi] Exclude Authenticated + [sdi] Exclude Visit Login Page + [DA] Exclude Single Page Visits.\n[sdi] Postpaid Flow (Exclude HSI + BYOD) - HIT-level exclusion removing any hit matching HSI identifiers.\nPage Name contains TLife App Shop HINT, TMO HINT, or TMO:UNO HINT.\nPage URL contains www.t-mobile.com/isp, es.t-mobile.com/home-internet, www.t-mobile.com/home-internet, or www.t-mobile.com/stores/bd/home-internet.\nSite Name = TMO AND Site Section (v1) = HINT.\nPage Name contains TLife App Shop OR TMO Shop AND Product Type (v100) = ISP.\nBYOD SIM pages are NOT excluded at UVNB level - excluded at cart and orders only.\nUsed as denominator for Cart Postpaid CVR% and Orders Postpaid CVR%.' AS apx_build_details,'HSI PAGE HITS\nPROSPECT FILTERS' AS apx_excl_labels,'All hits matching HINT page names, /isp/ and /home-internet/ URLs, Site Section = HINT, Product Type = ISP.\nAll Layer 2 prospect filters also applied.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
UNION ALL SELECT 6 AS apx_sort_order,'uvnb_hsi_flow' AS apx_id,'UVNB - HSI Flow' AS apx_label,'Metric' AS apx_record_type,'Top Funnel' AS apx_funnel_stage,1 AS apx_funnel_sort,'UVNB' AS apx_category,6 AS apx_category_sort,'Home Internet (HSI)' AS apx_scope,'HSI' AS apx_lob,TRUE AS apx_is_subflow,'uvnb_actuals_overall' AS apx_parent_id,FALSE AS apx_subflows_summable,'Adobe Analytics -> BigQuery' AS apx_source_system,'BigQuery' AS apx_source_platform,'prj-dbi-prd-1.ds_dbi_digitalmedia_automation.vw_sdi_bronze_uvnbQgpActualsForecasts_weekly' AS apx_source_table,'Khalid / Ben' AS apx_data_owner,'Weekly - notebook run' AS apx_refresh_cadence,'Distinct non-bounced visitors who browsed T-Mobile Home Internet pages - the prospect audience for the internet service offering.' AS apx_definition,'Cannot be summed with Postpaid and BYOD flows to equal UVNB Actuals.' AS apx_sum_warning,'cart_hsi_flow' AS apx_cvr_numerator_id,'uvnb_hsi_flow' AS apx_cvr_denominator_id,'LAYER 1\nLAYER 2\nLAYER 3 - HSI INCLUSION\nHSI PAGE NAME\nHSI PAGE URL\nHSI SITE SECTION\nHSI PRODUCT TYPE\nCVR DENOMINATOR' AS apx_build_labels,'Universal filters.\nProspect qualifiers (same as UVNB Actuals).\n[DA] HSI Any HSI Site Page Hits - HIT-level inclusion where any hit matched HSI identifiers.\nPage Name contains TLife App Shop HINT, TMO HINT, or TMO:UNO HINT.\nPage URL contains www.t-mobile.com/isp, es.t-mobile.com/home-internet, www.t-mobile.com/home-internet, or www.t-mobile.com/stores/bd/home-internet.\nSite Name = TMO AND Site Section (v1) = HINT.\nPage Name contains TLife App Shop OR TMO Shop AND Product Type (v100) = ISP.\nUsed as denominator for Cart HSI CVR% and Orders HSI CVR%.' AS apx_build_details,'SCOPE\nMUTUAL EXCLUSIVITY' AS apx_excl_labels,'Scoped to visits containing any HSI page hit. All prospect filters applied.\nNot mutually exclusive from Postpaid or BYOD at visit level.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
UNION ALL SELECT 7 AS apx_sort_order,'uvnb_byod_flow' AS apx_id,'UVNB - BYOD Flow' AS apx_label,'Metric' AS apx_record_type,'Top Funnel' AS apx_funnel_stage,1 AS apx_funnel_sort,'UVNB' AS apx_category,7 AS apx_category_sort,'BYOD' AS apx_scope,'BYOD' AS apx_lob,TRUE AS apx_is_subflow,'uvnb_actuals_overall' AS apx_parent_id,FALSE AS apx_subflows_summable,'Adobe Analytics -> BigQuery' AS apx_source_system,'BigQuery' AS apx_source_platform,'prj-dbi-prd-1.ds_dbi_digitalmedia_automation.vw_sdi_bronze_uvnbQgpActualsForecasts_weekly' AS apx_source_table,'Khalid / Ben' AS apx_data_owner,'Weekly - notebook run' AS apx_refresh_cadence,'Distinct non-bounced visitors who browsed BYOD or device-switching pages - prospects exploring how to bring an existing device to T-Mobile.' AS apx_definition,'Cannot be summed with Postpaid and HSI flows to equal UVNB Actuals.' AS apx_sum_warning,'cart_byod_flow' AS apx_cvr_numerator_id,'uvnb_byod_flow' AS apx_cvr_denominator_id,'LAYER 1\nLAYER 2\nLAYER 3 - BYOD PAGES\nPAGE 1\nPAGE 2\nPAGE 3\nPAGE 4 (CONTAINS)\nPAGE 5\nPAGE 6 (HITS)\nPAGE 7 (HITS)\nPAGE 8 (HITS)\nPAGE 9 (HITS)\nCVR DENOMINATOR' AS apx_build_labels,'Universal filters.\nProspect qualifiers (same as UVNB Actuals).\nBYOD Pages - Visits. Includes visits where any page name or hit matched BYOD identifiers.\nTMO Shop Browse Bring Your Own Phone.\nTMO Support Resources Switch from Current Carrier.\nTMO Shop Browse Bring your own phone eligibility checker.\nPage Name contains TMO Shop switch.\nTMO Marketing Landing Page Quick Prospect Switching.\nTMO Shop Cell Phone Detail T-Mobile SIM Card.\nTLife App Shop Cell Phone Detail T-Mobile SIM Card.\nTLife App Shop Tablet Detail Mobile Internet SIM Card.\nTMO Shop Tablet Detail T-Mobile Mobile Internet SIM Card.\nUsed as denominator for Cart BYOD CVR% and Orders BYOD CVR%.' AS apx_build_details,'SCOPE\nMUTUAL EXCLUSIVITY' AS apx_excl_labels,'Scoped to visits containing any BYOD or SIM card page hit. All prospect filters applied.\nNot mutually exclusive from other flows at visit level.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
UNION ALL SELECT 8 AS apx_sort_order,'vr_calls' AS apx_id,'VR Calls' AS apx_label,'Metric' AS apx_record_type,'Mid Funnel' AS apx_funnel_stage,2 AS apx_funnel_sort,'VR Actions' AS apx_category,8 AS apx_category_sort,'All / Postpaid' AS apx_scope,'All' AS apx_lob,FALSE AS apx_is_subflow,CAST(NULL AS STRING) AS apx_parent_id,TRUE AS apx_subflows_summable,'Quarterly Game Plan (QGP)' AS apx_source_system,'Databricks' AS apx_source_platform,'prdrzrlakehouse.qgp_restricted.qgpweeklyview' AS apx_source_table,'Preeti Laharwani / Bharat Kavuru' AS apx_data_owner,'Daily at 9 AM PT' AS apx_refresh_cadence,'Phone calls placed by customers clicking a T-Mobile.com phone number to get live sales help - a direct signal of high purchase intent.' AS apx_definition,CAST(NULL AS STRING) AS apx_sum_warning,CAST(NULL AS STRING) AS apx_cvr_numerator_id,CAST(NULL AS STRING) AS apx_cvr_denominator_id,'SOURCE\nHOW IT IS BUILT\nTRIGGER\nFORECAST\nACT VS FCST %\nQTD SUM\nREFRESH' AS apx_build_labels,'QGP operational data - entirely separate from Adobe Analytics. No Adobe segment filtering applies.\nCounts customer calls handled by T-Mobile Virtual Retail (VR) sales teams.\nTriggered when a customer clicks a phone number on T-Mobile.com to get assistance purchasing a device or plan.\nQGP provides both weekly actuals and a weekly forecast (VR Calls QGP).\n(Actuals minus QGP Forecast) / QGP Forecast.\nRunning total from Q2 start.\nDaily at 9 AM PT.' AS apx_build_details,'ADOBE FILTERING' AS apx_excl_labels,'No Adobe segment filtering. QGP operational data only.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
UNION ALL SELECT 9 AS apx_sort_order,'vr_chats' AS apx_id,'VR Chats' AS apx_label,'Metric' AS apx_record_type,'Mid Funnel' AS apx_funnel_stage,2 AS apx_funnel_sort,'VR Actions' AS apx_category,9 AS apx_category_sort,'All / Postpaid' AS apx_scope,'All' AS apx_lob,FALSE AS apx_is_subflow,CAST(NULL AS STRING) AS apx_parent_id,TRUE AS apx_subflows_summable,'Quarterly Game Plan (QGP)' AS apx_source_system,'Databricks' AS apx_source_platform,'prdrzrlakehouse.qgp_restricted.qgpweeklyview' AS apx_source_table,'Preeti Laharwani / Bharat Kavuru' AS apx_data_owner,'Daily at 9 AM PT' AS apx_refresh_cadence,'Chat conversations initiated by customers on T-Mobile.com with Virtual Retail sales agents - indicating purchase-ready engagement.' AS apx_definition,CAST(NULL AS STRING) AS apx_sum_warning,CAST(NULL AS STRING) AS apx_cvr_numerator_id,CAST(NULL AS STRING) AS apx_cvr_denominator_id,'SOURCE\nHOW IT IS BUILT\nTRIGGER\nFORECAST\nACT VS FCST %\nREFRESH' AS apx_build_labels,'QGP operational data - no Adobe segment filtering.\nCounts customer chat conversations handled by T-Mobile VR sales teams.\nTriggered when a customer clicks to chat on T-Mobile.com to get help purchasing a device or plan.\nQGP provides both actuals and a weekly forecast.\n(Actuals minus QGP Forecast) / QGP Forecast.\nDaily at 9 AM PT.' AS apx_build_details,'ADOBE FILTERING' AS apx_excl_labels,'No Adobe segment filtering. QGP operational data only.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
UNION ALL SELECT 10 AS apx_sort_order,'exit_traffic_door_swings' AS apx_id,'Exit Traffic (Door Swings)' AS apx_label,'Metric' AS apx_record_type,'Mid Funnel' AS apx_funnel_stage,2 AS apx_funnel_sort,'Retail Actions' AS apx_category,10 AS apx_category_sort,'Retail' AS apx_scope,'All' AS apx_lob,FALSE AS apx_is_subflow,CAST(NULL AS STRING) AS apx_parent_id,TRUE AS apx_subflows_summable,'Quarterly Game Plan (QGP)' AS apx_source_system,'Databricks' AS apx_source_platform,'prdrzrlakehouse.qgp_restricted.qgpweeklyview' AS apx_source_table,'Preeti Laharwani / Bharat Kavuru' AS apx_data_owner,'Daily at 9 AM PT' AS apx_refresh_cadence,'Total customer entries/exits at T-Mobile retail stores each week, measured by door-swing sensors - a proxy for offline foot traffic.' AS apx_definition,CAST(NULL AS STRING) AS apx_sum_warning,CAST(NULL AS STRING) AS apx_cvr_numerator_id,CAST(NULL AS STRING) AS apx_cvr_denominator_id,'SOURCE\nHOW IT IS BUILT\nDATA COLLECTION\nFORECAST\nACT VS FCST %\nREFRESH' AS apx_build_labels,'QGP operational data sourced from retail door-swing sensor hardware - no Adobe segment filtering.\nCounts physical customer exits from T-Mobile retail store locations.\nData sourced from door-swing sensor readings at store entrances/exits, reported through QGP.\nQGP provides both actuals and a weekly forecast.\n(Actuals minus QGP Forecast) / QGP Forecast.\nDaily at 9 AM PT.' AS apx_build_details,'ADOBE FILTERING\nPURCHASE OUTCOME' AS apx_excl_labels,'Retail sensor data - no Adobe filtering.\nCounts all store visits regardless of purchase outcome.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
UNION ALL SELECT 11 AS apx_sort_order,'add_to_cart_overall' AS apx_id,'Add to Cart (Overall)' AS apx_label,'Metric' AS apx_record_type,'Mid Funnel' AS apx_funnel_stage,2 AS apx_funnel_sort,'Cart' AS apx_category,11 AS apx_category_sort,'Postpaid + HSI + BYOD' AS apx_scope,'All' AS apx_lob,FALSE AS apx_is_subflow,CAST(NULL AS STRING) AS apx_parent_id,TRUE AS apx_subflows_summable,'Adobe Analytics -> BigQuery (via Improvado)' AS apx_source_system,'BigQuery' AS apx_source_platform,'prj-dbi-prd-1.ds_dbi_improvado_master.adobe_cs_day_tmo' AS apx_source_table,'Improvado' AS apx_data_owner,'Daily at 9 AM PT' AS apx_refresh_cadence,'Total visits in which a prospect added any T-Mobile product to cart - the strongest digital signal of purchase intent before checkout.' AS apx_definition,CAST(NULL AS STRING) AS apx_sum_warning,'add_to_cart_overall' AS apx_cvr_numerator_id,'uvnb_actuals_overall' AS apx_cvr_denominator_id,'DERIVED TOTAL\nBASE METRIC\nLAYER 1\nLAYER 2\nLAYER 3 - CART START\nCART PAGE URLS\nCART PAGE NAMES\nBYOD CART PAGE\nLAYER 4\nCVR %\nREFRESH' AS apx_build_labels,'Add to Cart = Cart Postpaid Flow + Cart HSI Flow + Cart BYOD Flow. Flows CAN be summed - mutually exclusive filtering.\nCount of VISITS where a prospect performs a cart start action (scAdd or scOpen) on a recognized cart page.\nUniversal filters.\nProspect qualifiers: Exclude TMO Mobile Network Carrier + [sdi] Exclude Authenticated + [sdi] Exclude Visit Login Page + [DA] Exclude Single Page Visits.\n[sdi] cart start - requires scOpen OR scAdd on a recognized cart page.\nwww.t-mobile.com/shopping-cart | www.t-mobile.com/cart | es.t-mobile.com/cart | es.t-mobile.com/shopping-cart.\nTMO:UNO Shop Cart | TMO Shop Cart | TLife App Shop Cart Active Cart | TMO Shop Cart Active Cart.\nTMO Shop Switch Checkout Review AND Cart Views (scView) exists AND Product Name (v35) = BYOS SIM or eSIM.\nFlow-specific filters applied differently per sub-flow - see Cart flow rows.\nAdd to Cart / UVNB Actuals.\nDaily at 9 AM PT.' AS apx_build_details,'PROSPECT FILTERS\nSUB-FLOW EXCLUSIONS' AS apx_excl_labels,'All prospect filters applied.\nFlow-specific exclusions detailed in each sub-flow row below.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
UNION ALL SELECT 12 AS apx_sort_order,'cart_postpaid_flow' AS apx_id,'Cart - Postpaid Flow' AS apx_label,'Metric' AS apx_record_type,'Mid Funnel' AS apx_funnel_stage,2 AS apx_funnel_sort,'Cart' AS apx_category,12 AS apx_category_sort,'Postpaid' AS apx_scope,'Postpaid' AS apx_lob,TRUE AS apx_is_subflow,'add_to_cart_overall' AS apx_parent_id,TRUE AS apx_subflows_summable,'Adobe Analytics -> BigQuery (via Improvado)' AS apx_source_system,'BigQuery' AS apx_source_platform,'prj-dbi-prd-1.ds_dbi_improvado_master.adobe_cs_day_tmo' AS apx_source_table,'Improvado' AS apx_data_owner,'Daily at 9 AM PT' AS apx_refresh_cadence,'Visits in which a prospect started or added to a cart on the Postpaid path, with all HSI and BYOD cart activity removed.' AS apx_definition,'Sums with Cart HSI + Cart BYOD = Add to Cart total.' AS apx_sum_warning,'cart_postpaid_flow' AS apx_cvr_numerator_id,'uvnb_postpaid_flow' AS apx_cvr_denominator_id,'LAYERS 1-3\nLAYER 4 - HSI CART EXCL\nHSI PRODUCT TYPE\nHSI FLOW NAME\nHSI URLS\nLAYER 4 - BYOD CART EXCL\nBYOD PRODUCT TYPE\nBYOD CHECKOUT PAGE\nBYOD FLOW NAME\nEXISTING CUSTOMER SCRUB\nCUSTOMER SIGNALS\nTRACKING CODES\nLOGIN SIGNALS\nSPRINT/CUSTOMER IND.\nCVR %' AS apx_build_labels,'Universal + Prospect + [sdi] cart start (same as Add to Cart overall).\n[sdi] Exclude HSI OR BYOD Cart Start - removes HSI cart activity from Postpaid count.\nCart pages where Product Type (v100) = ISP.\nFlow Name (v154) = AAL Intent (HSI checkout initiation).\nURLs containing .t-mobile.com/home-internet/eligibility/base or /commerce/checkout/hint-order.\nRemoves BYOD cart activity from Postpaid count.\nCart pages where Product Type (v100) = SIMCARDS.\nTMO Shop Switch Checkout Review AND Cart Views (scView) exists AND Product Name (v35) = BYOS SIM or eSIM.\nFlow Name (v154) starts with DEFERRED Intent, Prospect Activation, or Activation Intent.\nAdditional scrub beyond Layer 2 for existing customer signals.\nMobile Carrier Network = T-Mobile | Encrypted MSISDN (v121) exists.\nTracking Code (v0) contains _TMT_, _C_, or _CUST_.\nSuccessful Logins (e4) exists | Page contains web2go | Site Section = ma | my.t-mobile.com in URL.\nSite Name contains Sprint | Customer Indicators (v155) contains m:1 or b:1.\nCart Postpaid Flow / UVNB Postpaid Flow.' AS apx_build_details,'HSI AND BYOD CART\nCUSTOMER SIGNAL SCRUB' AS apx_excl_labels,'Removes HSI and BYOD cart actions from Postpaid count.\nAdditional existing-customer signal scrub: MSISDN, tracking codes, Sprint site, Customer Indicators.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
