UNION ALL SELECT 14 AS apx_sort_order,'cart_byod_flow' AS apx_id,'Cart - BYOD Flow' AS apx_label,'Metric' AS apx_record_type,'Mid Funnel' AS apx_funnel_stage,2 AS apx_funnel_sort,'Cart' AS apx_category,14 AS apx_category_sort,'BYOD' AS apx_scope,'BYOD' AS apx_lob,TRUE AS apx_is_subflow,'add_to_cart_overall' AS apx_parent_id,TRUE AS apx_subflows_summable,'Adobe Analytics -> BigQuery (via Improvado)' AS apx_source_system,'BigQuery' AS apx_source_platform,'prj-dbi-prd-1.ds_dbi_improvado_master.adobe_cs_day_tmo' AS apx_source_table,'Improvado' AS apx_data_owner,'Daily at 9 AM PT' AS apx_refresh_cadence,'Visits in which a prospect added a SIM card or BYOD product to cart on the device-switching path.' AS apx_definition,'Part of Add to Cart total.' AS apx_sum_warning,'cart_byod_flow' AS apx_cvr_numerator_id,'uvnb_byod_flow' AS apx_cvr_denominator_id,'LAYERS 1-2\nLAYER 3 - BYOD CART\nCONDITION 1 - CART EVENT\nCONDITION 2 - PRODUCT\nCONDITION 3 - FLOW NAME\nFLOW NAME VALUES\nCVR %' AS apx_build_labels,'Universal + Prospect.\n[sdi] postpaid prospect byod cart start hit - includes HITS where ALL three conditions are true.\nscOpen OR scAdd on a recognized cart page.\nProduct Type (v100) = SIMCARDS | TMO Shop Switch Checkout Review AND Cart Views (scView) exists AND Product Name (v35) = BYOS SIM or eSIM.\nFlow Name (v154) = active prospect activation intent.\nStarts with DEFERRED Intent | = Prospect Activation Intent | = Intencion de activacion de prospecto Intent | = Activacion de prospecto Intent | Starts with Activation Intent.\nCart BYOD Flow / UVNB BYOD Flow.' AS apx_build_details,'SCOPE\nEXCLUDED FLOWS' AS apx_excl_labels,'Scoped to SIM card product type with active prospect activation flow.\nExcludes Postpaid device and HSI cart actions.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
UNION ALL SELECT 15 AS apx_sort_order,'orders_unassisted_overall' AS apx_id,'Orders (Unassisted)' AS apx_label,'Metric' AS apx_record_type,'Bottom Funnel' AS apx_funnel_stage,3 AS apx_funnel_sort,'Orders Unassisted' AS apx_category,15 AS apx_category_sort,'Postpaid + HSI + BYOD' AS apx_scope,'All' AS apx_lob,FALSE AS apx_is_subflow,CAST(NULL AS STRING) AS apx_parent_id,TRUE AS apx_subflows_summable,'Adobe Analytics -> BigQuery (via Improvado)' AS apx_source_system,'BigQuery' AS apx_source_platform,'prj-dbi-prd-1.ds_dbi_improvado_master.sdi_raw_adobe_pp_pulse_pro_orders_unassisted_daily_tmo' AS apx_source_table,'Improvado' AS apx_data_owner,'Daily at 9 AM PT' AS apx_refresh_cadence,'Total orders completed entirely online with no T-Mobile employee involvement - the purest measure of self-serve digital conversion.' AS apx_definition,CAST(NULL AS STRING) AS apx_sum_warning,'orders_unassisted_overall' AS apx_cvr_numerator_id,'uvnb_actuals_overall' AS apx_cvr_denominator_id,'DERIVED TOTAL\nUNASSISTED FLAG\nIN-STORE SIGNAL 1\nIN-STORE SIGNAL 2\nIN-STORE SIGNAL 3\nIN-STORE SIGNAL 4\nSCREEN-SHARE SIGNAL 1\nSCREEN-SHARE SIGNAL 2\nSCREEN-SHARE SIGNAL 3\nCVR %\nREFRESH' AS apx_build_labels,'Orders (Unassisted) = Orders Postpaid Flow + Orders HSI Flow + Orders BYOD Flow. Flows CAN be summed.\nSourced from Adobe Analytics via [DA] Unassisted Proxy (No In-Store or Screen Share) - NOT a join against QGP.\nModal Name (v82) contains Buy online while in store is available.\nShipping Method (v27) contains while in store or Comprar por Internet desde una tienda.\nTracking Code Visit Level Expiration (v45) = MGPO_RS_P_PPMGNWLRSU_9FED46B36BD7D485135485.\nShipping Methods Displayed (v9) contains online while in store.\nAlert Message (v94) = Message: Screen share in progress.\nPage Name = TLife App Support Screen Share Share This Code AND Action Name = Button Click Allow.\nPage URL (v6) contains assist.t-mobile.\nOrders (Unassisted) / UVNB Actuals.\nDaily at 9 AM PT.' AS apx_build_details,'IN-STORE ORDERS\nSCREEN-SHARE\nANDROID GHOST HITS' AS apx_excl_labels,'Removes in-store-assisted orders (modal, shipping method, tracking code).\nScreen-share sessions removed.\nAndroid native app ghost order hits (no Order ID) removed.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
