UNION ALL SELECT 23 AS apx_sort_order,'new_bans_digital_unassisted' AS apx_id,'New BANs - Digital Unassisted' AS apx_label,'Metric' AS apx_record_type,'Bottom Funnel' AS apx_funnel_stage,3 AS apx_funnel_sort,'New BANs' AS apx_category,23 AS apx_category_sort,'Consumer Postpaid' AS apx_scope,'Postpaid' AS apx_lob,FALSE AS apx_is_subflow,CAST(NULL AS STRING) AS apx_parent_id,TRUE AS apx_subflows_summable,'Quarterly Game Plan (QGP)' AS apx_source_system,'Databricks' AS apx_source_platform,'prdrzrlakehouse.qgp_restricted.qgpweeklyview' AS apx_source_table,'Preeti Laharwani / Bharat Kavuru (Forecast: Sheenu Thakran team)' AS apx_data_owner,'Daily at 9 AM PT' AS apx_refresh_cadence,'New billing accounts activated through digital self-serve - operational confirmation that a digital order resulted in a new T-Mobile Postpaid line being turned on.' AS apx_definition,CAST(NULL AS STRING) AS apx_sum_warning,CAST(NULL AS STRING) AS apx_cvr_numerator_id,CAST(NULL AS STRING) AS apx_cvr_denominator_id,'SOURCE\nMETRIC\nWHAT IS A BAN\nWHAT IS A NEW BAN\nDOWNSTREAM CONFIRMATION\nFORECAST\nACT VS FCST %\nPCT OF CONSUMER\nREFRESH' AS apx_build_labels,'QGP operational data - no Adobe segment filtering.\nConsumer Postpaid Digital No Assistance New BAN activations.\nA BAN (Billing Account Number) = a unique T-Mobile customer account ID.\nA New BAN = a brand-new account.\nDownstream operational confirmation that a completed digital order translated into an active line.\nQGP provides actuals and a weekly forecast (Sheenu Thakran team).\n(Actuals minus QGP Forecast) / QGP Forecast.\nNew BANs Dig Unassist divided by total Consumer Postpaid new BANs (digital + assisted combined).\nDaily at 9 AM PT.' AS apx_build_details,'ADOBE FILTERING\nSCOPE' AS apx_excl_labels,'QGP operational metric - no Adobe filtering.\nCounts Digital No Assistance (self-serve) activations only.' AS apx_excl_details,CAST(NULL AS STRING) AS apx_glossary_category
